import React, { useContext } from "react";
import { StoreContext } from "../controllers/store";

export default function HighestID () {
    const store = useContext(StoreContext);

    let players_list = [];

    store.state.servers.forEach((server, index) => {
        if(server.playersData) players_list.push(...server.playersData);
    });

    players_list =  players_list
                        .sort((a,b) => b[2] - a[2])
                        .map((data, index) => ({
                                index: index+1, 
                                name: data[0], 
                                id: data[2]
                        }));

    const final_list = players_list.length > 25 ? 
                        [
                            ...players_list.splice(0, 10),
                            {
                                index: '...', 
                                name: '...', 
                                id: '...'
                            },
                            ...players_list.splice(players_list.length-10)
                        ] : players_list;


    return (
        <div className="container">
            <div className="border-start">
                <div className="border-title">Highest and lowest player IDs currently online</div>
                {!store.state.inited && <div className="border-title">Loading</div>}
                <div className="border-end">
                    {store.state.inited && 
                        <table>
                            <thead>
                                <tr>
                                    <th>#</th>
                                    <th>Name</th>
                                    <th>ID</th>
                                </tr>
                            </thead>
                            <tbody>
                                {final_list.length === 0 ? <tr><th></th><th>No Players Found</th><th></th></tr> : 
                                    final_list.map((player, index) => (
                                        <tr key={index} style={index === 0 ? {fontSize: '2em'} : {}}>
                                            <td data-label="# Place">#{player.index}</td>
                                            <td data-label="Player"><b>{player.name ? player.name : "?"}</b></td>
                                            <td data-label="ID">{player.id}</td>
                                        </tr>
                                    ))
                                }
                            </tbody>
                        </table>
                    }
                </div>
            </div>
        </div>
    )
}