import servers_list from "./serverslist.json";

export const initAllServers = () => dispatch => {
    dispatch({type: "CLEARSERVERSLIST"})

    servers_list.forEach((server, index) => {
        dispatch({
            type: "ADDSERVER",
            data: {
                "error": null,
                "isLoaded": false,
                "name": server[1],
                "sname": server[2],
                "endpoint": server[0],
                "playersData": null,
                "serverData": null,
                "lastUpdate": null,
                "vehicleData": null,
            },
            index
        });

        fetchServer(server[0], index)(dispatch);
    });

    dispatch({type: "SERVERSINITED"});
};

export const fetchServer = (server_endpoint, index) => async dispatch => {
    const cancelController = new AbortController();
    const cancelControllerTimeout = setTimeout(() => { cancelController.abort(); }, 5000);

    fetch(`https://tycoon-${server_endpoint}.users.cfx.re/status/widget/players.json`, { signal: cancelController.signal })
    .then(res => res.json())
    .then(res => {
        if(!("server" in res)) throw new Error();

        for (let i = 0; i < res.players.length; i++) {
            if(res.players[i][5] === "") res.players[i][5] = "Unemployed";
        }
        
        dispatch({
            type: "UPDATESERVER",
            data: {
                isLoaded: true,
                playersData: res.players,
                serverData: res.server,
                lastUpdate: Date.now()
            },
            index
        })
    }).catch(() => {
        clearTimeout(cancelControllerTimeout);
        setTimeout(() => { cancelController.abort(); }, 5000);

        fetch(`https://servers-frontend.fivem.net/api/servers/single/${server_endpoint}`, { signal: cancelController.signal })
        .then(res => res.json())
        .then(res => {
            if(!("Data" in res)) throw new Error();
            const data = res["Data"];
            dispatch({
                type: "UPDATESERVER",
                data: {
                    isLoaded: true,
                    playersData: data.players.map(player => [
                        player.name || "?",
                        -1,
                        "?",
                        null,
                        false,
                        "?",
                        false
                    ]),
                    serverData: {
                        "limit": data?.["sv_maxclients"] || 32,
                        "beta": "",
                        "dxp": [false],
                        "uptime": data?.["vars"]?.["Uptime"] || "1m",
                        "region": "?",
                        "number": "?",
                        "name": "",
                        "motd": ""
                    },
                    lastUpdate: Date.now()
                },
                index
            })
            
        }).catch(() => {
            dispatch({
                type: "UPDATESERVER",
                data: {
                    isLoaded: true,
                    error: true,
                    lastUpdate: Date.now()
                },
                index
            })
        });
    });
}