import React from "react";
import {
  BrowserRouter as Router,
  Route,
  Link,
  Redirect,
  Switch
} from "react-router-dom";
import { StoreProvider } from '../controllers/store';
import ServersStatus from "./ServersStatus";
import ServerInfo from "./ServerInfo";
import PlayerFinder from "./PlayerFinder";
import TopJobs from "./TopJobs";
import TopVehicles from "./TopVehicles";
import TopTen from "./TopTen";
import RefreshButton from "../subcomponents/RefreshButton";
import HighestID from "./HighestID";

export default function App() {

	return (
		<Router basename="/">
		{/* <Router basename="ttstats"> */}
		<StoreProvider>
      <div id="header">
        <div className="container">
        <div className="border-start">
          <div className="border-title">
            <div className="flex">
              <div>
                <a href="https://ttstats.eu">ttstats.eu</a>
              </div>
              <div>
                <RefreshButton/>
              </div>
            </div>
          </div>
          <div className="border-end">
            <ul>
              <li><Link to="/">Servers Status</Link></li>
              <li><Link to="/playerfinder">Player Finder</Link></li>
              <li><Link to="/vehicles">Top Vehicles</Link></li>
              <li><Link to="/jobs">Top Jobs</Link></li>
              <li><Link to="/top10">Top 10</Link></li>
              <li><Link to="/highest_id">Highest Player ID</Link></li>
              {/* <li><Link to="?uptime">Uptime</Link></li> */}
              {/* <li><a href="http://ttmap.aca.lt" className="gold">ttmap.aca.lt</a></li> */}
            </ul>
          </div>
          </div>
        </div>
      </div>

      <div id="content">
        <Switch>
          <Route path="/playerfinder">
            <PlayerFinder />
          </Route>
          <Route path="/jobs">
            <TopJobs/>
          </Route>
          <Route path="/vehicles">
            <TopVehicles/>
          </Route>
          <Route path="/top10">
            <TopTen/>
          </Route>
          <Route path="/highest_id">
            <HighestID/>
          </Route>
          <Route path="/">
            <ServersStatus />
          </Route>
        </Switch>

        {/* <Route component={
          (props)=>{
            const url = props.location.search.split("=");
            switch(url[0]){
              case ("?status"):
              case (""):
                return <ServersStatus/>;
              case ("?serverinfo"):
                return <ServerInfo url={url}/>;
              case ("?jobs"):
                return <TopJobs/>;
              case ("?vehicles"):
                return <TopVehicles/>;
              case ("?top10"):
                return <TopTen/>;
              case ("?playerfinder"):
                return <PlayerFinder url={url}/>;
              case ("?highest_id"):
                return <HighestID/>;
              default:
                return <Redirect to="?status"/>;
            }
          }}/> */}
        </div>
      </StoreProvider>
    </Router>
  );
}
